import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';

export default function StudentDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [profile, setProfile] = useState(null);
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([axios.get('/students/profile'), axios.get('/fees/my')])
      .then(([p, f]) => { setProfile(p.data); setFees(f.data); })
      .catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height:300 }}><div className="spinner" /></div>;

  const paid = fees.filter(f => f.status === 'paid');
  const pending = fees.filter(f => f.status === 'pending' || f.status === 'overdue');
  const overdue = fees.filter(f => f.status === 'overdue');
  const totalPaid = paid.reduce((s,f) => s+parseFloat(f.totalAmount), 0);
  const totalPending = pending.reduce((s,f) => s+parseFloat(f.totalAmount), 0);
  const fmt = n => `₹${Number(n).toLocaleString('en-IN')}`;

  const nextDue = pending.sort((a,b) => new Date(a.dueDate)-new Date(b.dueDate))[0];
  const daysUntil = date => Math.ceil((new Date(date)-new Date())/(1000*60*60*24));

  const pieData = [
    { name:'Paid', value:paid.length, color:'#10b981' },
    { name:'Pending', value:pending.length, color:'#f59e0b' },
  ].filter(d=>d.value>0);

  return (
    <div>
      {/* Hero */}
      <div className="student-hero">
        <h2>👋 Welcome back, {user?.name?.split(' ')[0]}!</h2>
        <p>Here's your bus fee overview for this academic year</p>
        <div className="student-info-grid">
          {profile && <>
            <div className="student-info-item"><span className="label">ID</span><span className="val">{profile.studentId}</span></div>
            <div className="student-info-item"><span className="label">Dept</span><span className="val">{profile.department}</span></div>
            <div className="student-info-item"><span className="label">Year</span><span className="val">Year {profile.year}</span></div>
            {profile.route && <div className="student-info-item"><span className="label">Route</span><span className="val">🚌 {profile.route.routeNumber}</span></div>}
            {profile.boardingPoint && <div className="student-info-item"><span className="label">Boarding</span><span className="val">📍 {profile.boardingPoint}</span></div>}
          </>}
        </div>
      </div>

      {/* Alerts */}
      {overdue.length > 0 && (
        <div className="alert alert-error">
          ⚠️ You have <strong>{overdue.length} overdue fee(s)</strong> totaling <strong>{fmt(overdue.reduce((s,f)=>s+parseFloat(f.totalAmount),0))}</strong>. Please contact the admin immediately!
        </div>
      )}
      {nextDue && overdue.length === 0 && (
        <div className={`alert ${daysUntil(nextDue.dueDate) <= 3 ? 'alert-error' : daysUntil(nextDue.dueDate) <= 7 ? 'alert-warning' : 'alert-info'}`}>
          {daysUntil(nextDue.dueDate) <= 0 ? '🔴' : daysUntil(nextDue.dueDate) <= 3 ? '🟠' : '🟡'} Next payment of <strong>{fmt(nextDue.totalAmount)}</strong> for <strong>{nextDue.feeMonth}</strong> is due on <strong>{nextDue.dueDate}</strong>
          {daysUntil(nextDue.dueDate) > 0 && ` (${daysUntil(nextDue.dueDate)} days left)`}
        </div>
      )}

      {/* Stats */}
      <div className="stats-grid">
        <div className="stat-card green">
          <span className="stat-icon">✅</span>
          <div className="stat-label">Total Paid</div>
          <div className="stat-value" style={{ fontSize:22 }}>{fmt(totalPaid)}</div>
          <div className="stat-sub">{paid.length} payments made</div>
        </div>
        <div className="stat-card yellow">
          <span className="stat-icon">⏳</span>
          <div className="stat-label">Amount Pending</div>
          <div className="stat-value" style={{ fontSize:22 }}>{fmt(totalPending)}</div>
          <div className="stat-sub">{pending.length} fees due</div>
        </div>
        <div className="stat-card">
          <span className="stat-icon">💳</span>
          <div className="stat-label">Monthly Fee</div>
          <div className="stat-value" style={{ fontSize:22 }}>{profile?.route ? fmt(profile.route.monthlyFee) : '—'}</div>
          <div className="stat-sub">Per month</div>
        </div>
        <div className="stat-card blue">
          <span className="stat-icon">📋</span>
          <div className="stat-label">Total Records</div>
          <div className="stat-value">{fees.length}</div>
          <div className="stat-sub">Fee history</div>
          {fees.length > 0 && (
            <div className="progress-bar" style={{ marginTop:10 }}>
              <div className="progress-fill progress-green" style={{ width:`${Math.round((paid.length/fees.length)*100)}%` }} />
            </div>
          )}
        </div>
      </div>

      {/* Quick Actions */}
      <div style={{ marginBottom:24 }}>
        <div style={{ fontSize:12, fontWeight:700, color:'var(--text-muted)', marginBottom:12, textTransform:'uppercase', letterSpacing:1 }}>Quick Links</div>
        <div className="quick-actions">
          {[
            { icon:'💳', label:'View My Fees', action:() => navigate('/student/fees') },
            { icon:'📅', label:'Fee Schedule', action:() => navigate('/student/schedule') },
            { icon:'🧾', label:'Receipts', action:() => navigate('/student/fees') },
            { icon:'🔔', label:'Notifications', action:() => navigate('/student/notifications') },
            { icon:'👤', label:'My Profile', action:() => navigate('/student/profile') },
          ].map(a => <div key={a.label} className="quick-action" onClick={a.action}><span className="icon">{a.icon}</span><span>{a.label}</span></div>)}
        </div>
      </div>

      <div className="charts-grid">
        {/* Route Info */}
        {profile?.route && (
          <div className="card">
            <div className="card-header"><h3 className="card-title">🚌 My Bus Route</h3></div>
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              {[
                ['Route Number', profile.route.routeNumber],
                ['Route Name', profile.route.routeName],
                ['Boarding Point', profile.boardingPoint || '—'],
                ['Monthly Fee', fmt(profile.route.monthlyFee)],
                ['Fee Type', profile.feeType],
                ['Parent Contact', profile.parentPhone || '—'],
              ].map(([k,v]) => (
                <div key={k} style={{ display:'flex', justifyContent:'space-between', padding:'8px 0', borderBottom:'1px solid #f1f5f9', fontSize:13 }}>
                  <span style={{ color:'var(--text-muted)' }}>{k}</span>
                  <strong>{v}</strong>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Payment chart */}
        {pieData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title">📊 Payment Summary</h3></div>
            <ResponsiveContainer width="100%" height={180}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={50} outerRadius={75} paddingAngle={4} dataKey="value">
                  {pieData.map((e,i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div style={{ display:'flex', justifyContent:'center', gap:20, marginTop:8 }}>
              {pieData.map(d => (
                <div key={d.name} style={{ textAlign:'center' }}>
                  <div style={{ width:10, height:10, borderRadius:'50%', background:d.color, margin:'0 auto 4px' }} />
                  <div style={{ fontSize:12, color:'var(--text-muted)' }}>{d.name}</div>
                  <div style={{ fontWeight:700 }}>{d.value}</div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Recent fees */}
      <div className="card" style={{ marginTop:20 }}>
        <div className="card-header">
          <h3 className="card-title">📋 Recent Fee History</h3>
          <button className="btn btn-outline btn-sm" onClick={() => navigate('/student/fees')}>View All →</button>
        </div>
        {fees.length === 0 ? (
          <div className="empty-state"><span className="icon">📭</span><h3>No fee records yet</h3></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Month</th><th>Amount</th><th>Due Date</th><th>Paid On</th><th>Status</th></tr></thead>
              <tbody>
                {fees.slice(0,5).map(f => (
                  <tr key={f.id}>
                    <td><strong>{f.feeMonth}</strong></td>
                    <td>{fmt(f.totalAmount)}</td>
                    <td style={{ fontSize:12 }}>{f.dueDate}</td>
                    <td style={{ fontSize:12 }}>{f.paidDate || '—'}</td>
                    <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
